using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tool class wrapping a weather REST API.
/// The SDK discovers tools by scanning for [McpServerToolType] on the class
/// and [McpServerTool] on each public method. The [Description] attributes
/// are surfaced to the LLM so it understands when and how to call each tool.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _httpClient;

    // Constructor-injected HttpClient — the DI container resolves this
    // automatically via IHttpClientFactory when the SDK instantiates the tool.
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool, Description("Get the current weather forecast for a US location by latitude and longitude.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        // National Weather Service API: resolve grid point, then fetch forecast.
        var pointUrl = $"https://api.weather.gov/points/{latitude},{longitude}";
        var pointJson = await _httpClient.GetStringAsync(pointUrl);
        var point = JsonDocument.Parse(pointJson);
        var forecastUrl = point.RootElement
            .GetProperty("properties")
            .GetProperty("forecast")
            .GetString()!;

        var forecastJson = await _httpClient.GetStringAsync(forecastUrl);
        var forecast = JsonDocument.Parse(forecastJson);
        var periods = forecast.RootElement
            .GetProperty("properties")
            .GetProperty("periods");

        // Return the first three periods as a concise summary.
        var results = new List<string>();
        foreach (var period in periods.EnumerateArray().Take(3))
        {
            var name = period.GetProperty("name").GetString();
            var temp = period.GetProperty("temperature").GetInt32();
            var unit = period.GetProperty("temperatureUnit").GetString();
            var detail = period.GetProperty("detailedForecast").GetString();
            results.Add($"{name}: {temp}°{unit} — {detail}");
        }

        return string.Join("\n\n", results);
    }

    [McpServerTool, Description("Get active weather alerts for a US state (two-letter code, e.g. 'CA').")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code")] string state)
    {
        var url = $"https://api.weather.gov/alerts/active/area/{state}";
        var json = await _httpClient.GetStringAsync(url);
        var doc = JsonDocument.Parse(json);
        var features = doc.RootElement.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state}.";

        var alerts = new List<string>();
        foreach (var feature in features.EnumerateArray().Take(5))
        {
            var props = feature.GetProperty("properties");
            var headline = props.GetProperty("headline").GetString();
            var severity = props.GetProperty("severity").GetString();
            alerts.Add($"[{severity}] {headline}");
        }

        return string.Join("\n", alerts);
    }
}

