using McpServer;
using Microsoft.Extensions.DependencyInjection;
using ModelContextProtocol;

var builder = Host.CreateEmptyApplicationBuilder(settings: null);

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

// Register a named HttpClient for WeatherTools.
// The SDK uses IHttpClientFactory under the hood —
// any constructor parameter of type HttpClient is resolved per-invocation.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.weather.gov");
    client.DefaultRequestHeaders.UserAgent.ParseAdd("mcp-server/1.0");
});

var app = builder.Build();
await app.RunAsync();

